const error = $input.first().json;
const retryCount = error.retry_count || 0;
const maxRetries = 3;
const backoffMinutes = [1, 5, 30];

return [{
  json: {
    workflow_name: error.workflow?.name || 'unknown',
    node_name: error.execution?.lastNodeExecuted || 'unknown',
    error_type: error.execution?.error?.name || 'unknown',
    error_message: error.execution?.error?.message || 'No message',
    contact_id: error.execution?.data?.contact_id || '',
    retry_count: retryCount,
    max_retries: maxRetries,
    should_retry: retryCount < maxRetries,
    backoff_minutes: backoffMinutes[retryCount] || 30,
    timestamp: new Date().toISOString(),
    status: retryCount >= maxRetries ? 'needs_manual_review' : 'retrying'
  }
}];

parameters.text:
Workflow: {{$json.workflow_name}}
